#!/usr/bin/env node
// Generates docs/commands/_generated-table.md from api/commands.yaml.
//
// This is the ONLY place the full command table is rendered from — the
// authoritative data lives in api/commands.yaml (repo root), not here.
// commands/index.md includes the generated file via VitePress's markdown
// include syntax so the table can never silently drift out of sync with
// the YAML source of truth.
//
// Run via `npm run generate-commands`, which is wired as a pre-step of both
// `docs:dev` and `docs:build` (see package.json).

import { fileURLToPath } from "node:url";
import path from "node:path";
import fs from "node:fs";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const docsDir = path.resolve(__dirname, "..");
const repoRoot = path.resolve(docsDir, "..");

const commandsYamlPath = path.join(repoRoot, "api", "commands.yaml");
const outPath = path.join(docsDir, "commands", "_generated-table.md");

// Hand-rolled parser instead of a general YAML library. api/commands.yaml
// has a deliberately narrow, fixed shape (a flat list of records, each with
// exactly the fields name/category/phase/status/summary as plain scalars),
// and some `summary` values legitimately contain a colon-space sequence
// (e.g. "... (Phase 1: single workspace)") which strict YAML parsers reject
// in an unquoted plain scalar. Splitting each line on only the *first*
// colon-space avoids that ambiguity entirely, without needing to touch
// api/commands.yaml (out of scope for docs/) or add a YAML dependency.
function loadCommands() {
  const raw = fs.readFileSync(commandsYamlPath, "utf8");
  const lines = raw.split(/\r?\n/);

  const records = [];
  let current = null;

  for (const rawLine of lines) {
    const line = rawLine.trim();
    if (line === "" || line.startsWith("#")) continue;

    let entryLine = line;
    if (entryLine.startsWith("- ")) {
      if (current) records.push(current);
      current = {};
      entryLine = entryLine.slice(2).trim();
    }

    if (!current) {
      throw new Error(`generate-commands: unexpected line before any "- name:" entry: ${JSON.stringify(rawLine)}`);
    }

    const sep = entryLine.indexOf(": ");
    if (sep === -1) {
      throw new Error(`generate-commands: could not parse "key: value" from line: ${JSON.stringify(rawLine)}`);
    }
    const key = entryLine.slice(0, sep).trim();
    const value = entryLine.slice(sep + 2).trim();
    current[key] = value;
  }
  if (current) records.push(current);

  for (const r of records) {
    if (!r.name || !r.category || !r.phase || !r.status || !r.summary) {
      throw new Error(`generate-commands: incomplete record (missing a required field): ${JSON.stringify(r)}`);
    }
    r.phase = Number(r.phase);
  }

  return records;
}

function statusBadge(status) {
  if (status === "real") return "✅ Real";
  if (status === "planned") return "🔶 Planned";
  return status;
}

function escapeCell(value) {
  return String(value).replace(/\|/g, "\\|");
}

function render(commands) {
  const lines = [];
  lines.push(`<!-- AUTO-GENERATED by .vitepress/generate-commands.mjs from api/commands.yaml. -->`);
  lines.push(`<!-- Do not hand-edit this file — edit api/commands.yaml and regenerate instead. -->`);
  lines.push("");
  lines.push(`| Command | Category | Phase | Status | Summary |`);
  lines.push(`|---|---|---|---|---|`);
  for (const cmd of commands) {
    const name = escapeCell(cmd.name);
    const category = escapeCell(cmd.category);
    const phase = escapeCell(cmd.phase);
    const status = statusBadge(cmd.status);
    const summary = escapeCell(cmd.summary);
    lines.push(`| \`${name}\` | ${category} | ${phase} | ${status} | ${summary} |`);
  }
  lines.push("");
  const total = commands.length;
  const real = commands.filter((c) => c.status === "real").length;
  const planned = total - real;
  lines.push(`*${total} commands total: ${real} real (Phase 1), ${planned} planned (Phases 2-7). Generated from \`api/commands.yaml\`.*`);
  lines.push("");
  return lines.join("\n");
}

function main() {
  const commands = loadCommands();
  const content = render(commands);
  fs.mkdirSync(path.dirname(outPath), { recursive: true });
  fs.writeFileSync(outPath, content, "utf8");
  console.log(`generate-commands: wrote ${commands.length} commands to ${path.relative(repoRoot, outPath)}`);
}

main();
